import{_ as t,o,c as a,ag as r}from"./chunks/framework.DlJzNSsD.js";const p=JSON.parse('{"title":"Clawterm brand","description":"","frontmatter":{},"headers":[],"relativePath":"brand.md","filePath":"brand.md","lastUpdated":1778273951000}'),d={name:"brand.md"};function n(i,e,s,c,l,h){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="clawterm-brand" tabindex="-1">Clawterm brand <a class="header-anchor" href="#clawterm-brand" aria-label="Permalink to &quot;Clawterm brand&quot;">​</a></h1><p>Source of truth for what Clawterm <em>is</em> in brand terms — position, voice, color, type, mark, screenshots. Update this file before changing anything user-visible. The CI lint at <code>scripts/lint-tokens.sh</code> enforces the color/font tokens; the rest is on us.</p><h2 id="position" tabindex="-1">Position <a class="header-anchor" href="#position" aria-label="Permalink to &quot;Position&quot;">​</a></h2><p>Clawterm is a terminal for the agent era. Not an AI assistant for a terminal — a fast, native terminal that <em>expects</em> you to be running multiple agents and gives you the chrome to keep track of them.</p><p><strong>Reads as:</strong> calm, dense, professional — closer to Ghostty&#39;s monastic restraint than Warp&#39;s product-y gradients. Agent-aware features (status dots, attention indicators, OSC notifications) feel like instrumentation, not personality.</p><p><strong>Closest references:</strong> Ghostty&#39;s restraint + Linear&#39;s information density + Raycast&#39;s command-palette discipline.</p><p><strong>What we are not:</strong> Warp (block-based, AI-first marketing, gradients, animation flair). iTerm2 (legacy chrome, bevels, native macOS styling). Hyper (web-first, theme marketplace, plugin maximalism).</p><h2 id="voice" tabindex="-1">Voice <a class="header-anchor" href="#voice" aria-label="Permalink to &quot;Voice&quot;">​</a></h2><ul><li>Direct, technical, lowercase-friendly headings</li><li>No exclamation points, no marketing puff</li><li>Reference voice: the README&#39;s &quot;Highlights&quot; section</li><li>In-app strings should match that register</li></ul><h2 id="visual-axes" tabindex="-1">Visual axes <a class="header-anchor" href="#visual-axes" aria-label="Permalink to &quot;Visual axes&quot;">​</a></h2><ul><li><strong>Dark, not pitch-black.</strong> <code>--bg-base: #0c0c0e</code>, surface <code>#131316</code>, elevated <code>#1a1a1e</code>.</li><li><strong>Achromatic by default, color only for state.</strong> Accent is intentionally near-white (<code>rgba(240, 240, 244, 0.8)</code>). Color appears only for status: red error, green success, orange warning. <code>--color-purple-signal</code> is a fourth signal hue used for Claude compaction indicators — kept as a tokenized exception rather than expanded into a full status tier.</li><li><strong>Generous negative space, dense type.</strong> Small font sizes (12–14px primary, 10–11px chrome), tight letter-spacing, breathing room around clusters.</li><li><strong>Restraint over decoration.</strong> No gradients. No glows beyond the minimal <code>box-shadow</code> calls that mark &quot;compaction imminent.&quot; No glass-morphism / backdrop-filter. The existing <code>--shadow-sm</code> / <code>--shadow-lg</code> are the only depth cues.</li></ul><h2 id="color-tokens" tabindex="-1">Color tokens <a class="header-anchor" href="#color-tokens" aria-label="Permalink to &quot;Color tokens&quot;">​</a></h2><p>Defined in <code>src/style.css :root</code>. Reference via <code>var(--*)</code> only — the lint script fails CI on hardcoded hex values outside <code>:root</code>.</p><table tabindex="0"><thead><tr><th>Token</th><th>Value</th><th>Use</th></tr></thead><tbody><tr><td><code>--bg-base</code></td><td><code>#0c0c0e</code></td><td>App background</td></tr><tr><td><code>--bg-surface</code></td><td><code>#131316</code></td><td>Panel surface</td></tr><tr><td><code>--bg-elevated</code></td><td><code>#1a1a1e</code></td><td>Focused pane, hover</td></tr><tr><td><code>--bg-modal</code></td><td><code>rgba(19, 19, 22, 0.97)</code></td><td>Modal background</td></tr><tr><td><code>--accent</code></td><td><code>rgba(240, 240, 244, 0.8)</code></td><td>Brand accent (near-white)</td></tr><tr><td><code>--color-red</code></td><td><code>#e5484d</code></td><td>Error state</td></tr><tr><td><code>--color-green</code></td><td><code>#30a46c</code></td><td>Success state</td></tr><tr><td><code>--color-orange</code></td><td><code>#f5a623</code></td><td>Warning state</td></tr><tr><td><code>--color-purple-signal</code></td><td><code>#bf7af0</code></td><td>Claude compaction signal — single special-case hue</td></tr><tr><td><code>--badge-info-bg</code> / <code>--badge-info-text</code></td><td>rgba(95,135,255,0.18) / <code>#a8c0ff</code></td><td>High-effort badge</td></tr><tr><td><code>--badge-warn-bg</code> / <code>--badge-warn-text</code></td><td>rgba(229,72,77,0.18) / <code>#ff8a8e</code></td><td>Max-effort badge</td></tr></tbody></table><p>Adding a new color? Add the token to <code>:root</code>, document semantic intent here, then use it.</p><h2 id="type" tabindex="-1">Type <a class="header-anchor" href="#type" aria-label="Permalink to &quot;Type&quot;">​</a></h2><ul><li><strong>UI:</strong> Inter Variable / Inter / system sans</li><li><strong>Mono:</strong> JetBrains Mono Variable / JetBrains Mono / SF Mono</li><li><strong>Scale:</strong> <code>--font-2xs</code> 8 · <code>--font-xs</code> 10 · <code>--font-sm</code> 11 · <code>--font-base</code> 12 · <code>--font-md</code> 13 · <code>--font-lg</code> 14 · <code>--font-2xl</code> 20</li><li><strong>Weights:</strong> <code>--font-weight-medium</code> 510 · <code>--font-weight-semibold</code> 590 (these are tuned to Inter Variable; non-variable fallbacks coerce to 500/600)</li><li><strong>Letter-spacing:</strong> <code>--letter-spacing-normal</code> (-0.01em) by default, <code>--letter-spacing-wide</code> (0.02em) for uppercase chrome (footer effort badges, status dots)</li></ul><h2 id="spacing" tabindex="-1">Spacing <a class="header-anchor" href="#spacing" aria-label="Permalink to &quot;Spacing&quot;">​</a></h2><p>Strict 4pt grid (#493). The scale is 4 / 8 / 12 / 16 / 20 / 24 / 32 → <code>--space-1</code> (2) · <code>--space-2</code> (4) · <code>--space-3</code> (8) · <code>--space-4</code> (12) · <code>--space-5</code> (16) · <code>--space-6</code> (20) · <code>--space-7</code> (24) · <code>--space-8</code> (32).</p><p>No off-grid values. The CI lint guards against new violations.</p><h2 id="naming" tabindex="-1">Naming <a class="header-anchor" href="#naming" aria-label="Permalink to &quot;Naming&quot;">​</a></h2><p>The product name is <strong>Clawterm</strong> — lowercase t. Not &quot;ClawTerm&quot;, not &quot;ClawTerminal&quot;, not &quot;clawterm&quot; mid-sentence (use the capitalized form when referring to the product). The CI lint at <code>scripts/lint-name.sh</code> fails on <code>ClawTerm</code> mixed-case in any tracked file outside this <code>brand.md</code>.</p><h2 id="mark" tabindex="-1">Mark <a class="header-anchor" href="#mark" aria-label="Permalink to &quot;Mark&quot;">​</a></h2><p>App icon, favicon, and OG image should derive from a single source SVG so they stay in sync. Today they&#39;re committed independently; consolidating to a single source SVG is tracked separately.</p><h2 id="screenshots" tabindex="-1">Screenshots <a class="header-anchor" href="#screenshots" aria-label="Permalink to &quot;Screenshots&quot;">​</a></h2><p>The README hero and <code>docs/screenshots/clawterm.png</code> are the canonical product images. When updating:</p><ul><li>Same window dimensions as the existing image (1280×800-ish, native macOS chrome cropped).</li><li>Same demo content: a project with three tabs in mixed states (running / waiting / errored), one tab expanded showing a split.</li><li>Dark wallpaper, traffic lights visible, no other windows.</li><li>Take both the hero and <code>docs/screenshots/*.png</code> in the same session — they should look like the same Clawterm.</li></ul><h2 id="non-goals" tabindex="-1">Non-goals <a class="header-anchor" href="#non-goals" aria-label="Permalink to &quot;Non-goals&quot;">​</a></h2><ul><li>Logo redesign — the current mark is fine.</li><li>New illustrations or marketing motion graphics.</li><li>Color expansion beyond the documented tokens.</li></ul>',29)])])}const m=t(d,[["render",n]]);export{p as __pageData,m as default};
